                    writer.WriteNumber("remaining_prints", projectStats.RemainingPrintsOption.Value!.Value);
                else
                    writer.WriteNull("remaining_prints");

            if (projectStats.RemainingPartsOption.IsSet)
                if (projectStats.RemainingPartsOption.Value != null)
                    writer.WriteNumber("remaining_parts", projectStats.RemainingPartsOption.Value!.Value);
                else
                    writer.WriteNull("remaining_parts");

            if (projectStats.BomTotalItemsOption.IsSet)
                writer.WriteNumber("bom_total_items", projectStats.BomTotalItemsOption.Value!.Value);

            if (projectStats.BomCompletedItemsOption.IsSet)
                writer.WriteNumber("bom_completed_items", projectStats.BomCompletedItemsOption.Value!.Value);

            if (projectStats.BomCostOption.IsSet)
                writer.WriteNumber("bom_cost", projectStats.BomCostOption.Value!.Value);
        }
    }
}
